<?php

use app\models\ChurchGroups;
use yii\bootstrap5\Html;
use yii\bootstrap5\Offcanvas;

$groups = ChurchGroups::find()->orderBy(['name' => SORT_ASC])->all();
Offcanvas::begin([
    'id' => 'offcanvasGroups',
    'title' => 'Church Groups:',
    'placement' => 'end',
    'options' => ['class' => 'offcanvas-scroll'],
]);
?>
<div class="list-group">
    <?php foreach ($groups as $group): ?>
        <a href="<?= \yii\helpers\Url::to(['site/writings', 'church_group_id' => $group->id]) ?>" class="list-group-item list-group-item-action">
            <strong><?= Html::encode($group->name) ?></strong>
            <br>
            <small class="text-muted"><?= count($group->writings) ?> writings</small>
        </a>
    <?php endforeach; ?>
</div>
<?php Offcanvas::end(); ?>

<?php
$js = <<<JS
    const offcanvasGroups = document.getElementById('offcanvasGroups');
    const toggleBtn = document.getElementById('toggleGroupsBtn');
    const scrollIcons = toggleBtn.querySelectorAll('.scroll-icon');
    const closeIcons = toggleBtn.querySelectorAll('.close-icon');

    offcanvasGroups.addEventListener('show.bs.offcanvas', function () {
        scrollIcons.forEach(icon => icon.classList.add('d-none'));
        closeIcons.forEach(icon => icon.classList.remove('d-none'));
        toggleBtn.classList.add('active');
    });

    offcanvasGroups.addEventListener('hide.bs.offcanvas', function () {
        scrollIcons.forEach(icon => icon.classList.remove('d-none'));
        closeIcons.forEach(icon => icon.classList.add('d-none'));
        toggleBtn.classList.remove('active');
    });
JS;
$this->registerJs($js);
?>